package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.ekalender.verwerken.RM2RekenenService;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereidingStatus;
import be.schaubroeck.lpb.tools.enumtypes.RekenLogStatus;
import be.schaubroeck.lpb.tools.enumtypes.StatusVoorbereiding;
import be.schaubroeck.lpb.tools.service.ElektronischeVoorbereidingService;
import be.schaubroeck.lpb.tools.service.ElektronischeVoorbereidingStatusService;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;

@Slf4j
@Lazy
@Service
public class VoorbereidingStatusService {

    @Autowired
    private ElektronischeVoorbereidingStatusService elektronischeVoorbereidingStatusService;
    @Autowired
    private ElektronischeVoorbereidingService elektronischeVoorbereidingService;
    @Autowired
    private RM2RekenenService rm2rekenService;

    public void updateVoorbereidingStatus(RekenVoorbereiding rekenVoorbereiding, Integer rekenBatchNr, StatusVoorbereiding status, String actor) {
        ElektronischeVoorbereiding voorbereiding = rekenVoorbereiding.getElektronischeVoorbereiding();
        Admin admin = rekenVoorbereiding.getAdmin();
        try {
            updateVoorbereidingStatus(voorbereiding, status, actor);
            updateVoorbereidingRekenBatchNr(voorbereiding, rekenBatchNr);
            updateKalenderStatus(rekenVoorbereiding, status, actor);
        } catch (Exception exception) {
            log.error("Fout bij veranderen status voorbereiding {} admin {}", voorbereiding.getVoorbereidingId(), admin.getId(), exception);
        }
    }

    public StatusVoorbereiding bepaalStatusVoorbereiding(RekenLogStatus status, boolean heeftReguls, boolean heeftWaarschuwingen) {
        if (status == RekenLogStatus.FATAL_ERROR || heeftReguls) {
            return StatusVoorbereiding.RM2_GEREKEND_MET_FOUTEN;
        } else if (heeftWaarschuwingen) {
            return StatusVoorbereiding.RM2_GEREKEND_MET_WAARSCHUWINGEN;
        } else {
            return StatusVoorbereiding.RM2_GEREKEND;
        }
    }

    private void updateVoorbereidingStatus(ElektronischeVoorbereiding voorbereiding, StatusVoorbereiding status, String actor) {
        List<ElektronischeVoorbereidingStatus> statussen = elektronischeVoorbereidingStatusService.findAllCurrentByVoorbereidingId(voorbereiding.getVoorbereidingId());
        ElektronischeVoorbereidingStatus voorbereidingStatus =
                statussen.stream().max(Comparator.comparing(ElektronischeVoorbereidingStatus::getIngaveTijdstip)).orElse(null);
        if (voorbereidingStatus != null) {
            voorbereidingStatus.setStatus(status);
            voorbereidingStatus.setActor(actor);

            elektronischeVoorbereidingStatusService.updateElektronischeVoorbereidingStatus(voorbereidingStatus);
        }
    }

    private void updateVoorbereidingRekenBatchNr(ElektronischeVoorbereiding voorbereiding, Integer rekenBatchNr) {
        ElektronischeVoorbereiding elektronischeVoorbereiding = elektronischeVoorbereidingService.getByVoorbereidingId(voorbereiding.getVoorbereidingId(), "");
        if (!Objects.equals(rekenBatchNr, elektronischeVoorbereiding.getRekenBatchNr())) {
            elektronischeVoorbereiding.setRekenBatchNr(rekenBatchNr);
            elektronischeVoorbereidingService.update(elektronischeVoorbereiding);
        }
    }

    private void updateKalenderStatus(RekenVoorbereiding rekenVoorbereiding, StatusVoorbereiding status, String actor) {
        if (rekenVoorbereiding.isEkalenderVoorbereidingStatus(status) && rekenVoorbereiding.isEkalenderVoorbereiding()) {
            log.debug("Is eKalender");

            Admin admin = rekenVoorbereiding.getAdmin();
            if (rekenVoorbereiding.isKalenderOpdracht()) {
                rm2rekenService.rekenenRM2Opdracht(admin, Collections.singletonList(rekenVoorbereiding.getKalAfsluitenOpdrachtId()), false, status, actor);
            } else {
                rm2rekenService.rekenenRM2(admin, Collections.singletonList(rekenVoorbereiding.getKalAfsluitenId()), false, status, actor);
            }
        }
    }
}
